    #[test]
    fn test_fcntl_cloexec() {
        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();

        // Open with O_CLOEXEC
        let fd = sys_open(
            &mut proc,
            &mut host,
            b"/tmp/test",
            O_RDWR | O_CLOEXEC,
            0o644,
        )
        .unwrap();

        // F_GETFD should return FD_CLOEXEC.
        let flags = sys_fcntl(&mut proc, fd, F_GETFD, 0).unwrap();
        assert_eq!(flags as u32, FD_CLOEXEC);

        // F_SETFD to clear FD_CLOEXEC.
        sys_fcntl(&mut proc, fd, F_SETFD, 0).unwrap();
        let flags = sys_fcntl(&mut proc, fd, F_GETFD, 0).unwrap();
        assert_eq!(flags, 0);
    }

    #[test]
    fn test_fcntl_getfl_setfl() {
        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();

        let fd = sys_open(&mut proc, &mut host, b"/tmp/test", O_RDWR, 0o644).unwrap();

        // F_GETFL should return O_RDWR (access mode).
        let flags = sys_fcntl(&mut proc, fd, F_GETFL, 0).unwrap() as u32;
        assert_eq!(flags & O_ACCMODE, O_RDWR);

        // F_SETFL to set O_NONBLOCK.
        sys_fcntl(&mut proc, fd, F_SETFL, O_NONBLOCK).unwrap();

        // F_GETFL should now have O_NONBLOCK set, but access mode preserved.
        let flags = sys_fcntl(&mut proc, fd, F_GETFL, 0).unwrap() as u32;
        assert_eq!(flags & O_ACCMODE, O_RDWR);
        assert_ne!(flags & O_NONBLOCK, 0);
    }

    #[test]
    fn test_lseek() {
        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();

        let fd = sys_open(&mut proc, &mut host, b"/tmp/test", O_RDWR, 0o644).unwrap();

        // SEEK_SET to 100
        let pos = sys_lseek(&mut proc, &mut host, fd, 100, SEEK_SET).unwrap();
        assert_eq!(pos, 100);

        // SEEK_CUR -10 -> 90
        let pos = sys_lseek(&mut proc, &mut host, fd, -10, SEEK_CUR).unwrap();
        assert_eq!(pos, 90);
    }

    #[test]
    fn lseek_errors_preserve_kernel_owned_offsets() {
        fn install_fd(
            proc: &mut Process,
            file_type: FileType,
            host_handle: i64,
            path: &[u8],
        ) -> (i32, usize) {
            let ofd_idx = proc
                .ofd_table
                .create(file_type, O_RDWR, host_handle, path.to_vec());
            let fd = proc
                .fd_table
                .alloc(crate::fd::OpenFileDescRef(ofd_idx), 0)
                .unwrap();
            (fd, ofd_idx)
        }

        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();

        let (dir_fd, dir_ofd) = install_fd(&mut proc, FileType::Directory, 71, b"/dir");
        {
            let ofd = proc.ofd_table.get_mut(dir_ofd).unwrap();
            ofd.offset = 4;
            ofd.dir_synth_state = 2;
            ofd.dir_entry_offset = 4;
        }
        assert_eq!(
            sys_lseek(&mut proc, &mut host, dir_fd, -1, SEEK_SET),
            Err(Errno::EINVAL)
        );
        let ofd = proc.ofd_table.get(dir_ofd).unwrap();
        assert_eq!((ofd.offset, ofd.dir_synth_state, ofd.dir_entry_offset), (4, 2, 4));

        let (proc_fd, proc_ofd) = install_fd(
            &mut proc,
            FileType::Regular,
            crate::procfs::PROCFS_DIR_HANDLE,
            b"/proc",
        );
        proc.ofd_table.get_mut(proc_ofd).unwrap().offset = 3;
        assert_eq!(
            sys_lseek(&mut proc, &mut host, proc_fd, -1, SEEK_SET),
            Err(Errno::EINVAL)
        );
        assert_eq!(proc.ofd_table.get(proc_ofd).unwrap().offset, 3);

        let (fb_fd, fb_ofd) = install_fd(
            &mut proc,
            FileType::CharDevice,
            VirtualDevice::Fb0.host_handle(),
            b"/dev/fb0",
        );
        assert_eq!(
            sys_lseek(&mut proc, &mut host, fb_fd, 7, SEEK_SET),
            Ok(7)
        );
        assert_eq!(
            sys_lseek(&mut proc, &mut host, fb_fd, i64::MAX, SEEK_CUR),
            Err(Errno::EOVERFLOW)
        );
        assert_eq!(proc.ofd_table.get(fb_ofd).unwrap().offset, 7);

        let synthetic_handle = crate::descriptor_backing::alloc_synthetic_regular();
        let (synthetic_fd, synthetic_ofd) = install_fd(
            &mut proc,
            FileType::Regular,
            synthetic_handle,
            b"/etc/mtab",
        );
        assert_eq!(
            sys_lseek(&mut proc, &mut host, synthetic_fd, 2, SEEK_SET),
            Ok(2)
        );
        assert_eq!(
            sys_lseek(
                &mut proc,
                &mut host,
                synthetic_fd,
                i64::MAX,
                SEEK_CUR,
            ),
            Err(Errno::EOVERFLOW)
        );
        assert_eq!(
            crate::descriptor_backing::current_offset(
                FileType::Regular,
                synthetic_handle,
                proc.ofd_table.get(synthetic_ofd).unwrap().offset,
            ),
            Ok(2)
        );
        crate::descriptor_backing::release_for_ofd(FileType::Regular, synthetic_handle);

        let memfd = sys_memfd_create(&mut proc, b"seek-overflow", 0).unwrap();
        sys_write(&mut proc, &mut host, memfd, b"abcdef").unwrap();
        assert_eq!(
            sys_lseek(&mut proc, &mut host, memfd, 2, SEEK_SET),
            Ok(2)
        );
        assert_eq!(
            sys_lseek(&mut proc, &mut host, memfd, i64::MAX, SEEK_END),
            Err(Errno::EOVERFLOW)
        );
        assert_eq!(
            sys_lseek(&mut proc, &mut host, memfd, 0, SEEK_CUR),
            Ok(2)
        );
    }

