    fn test_setuid_nonroot_to_other_uid_fails() {
        let mut proc = Process::new(1);
        sys_setuid(&mut proc, 7).unwrap();
        assert_eq!(sys_setuid(&mut proc, 99), Err(Errno::EPERM));
        assert_eq!(proc.uid, 7);
        assert_eq!(proc.euid, 7);
    }

