    #[test]
    fn test_match_virtual_device() {
        assert_eq!(
            match_virtual_device(b"/dev/null"),
            Some(VirtualDevice::Null)
        );
        assert_eq!(
            match_virtual_device(b"/dev/console"),
            Some(VirtualDevice::Null)
        );
        assert_eq!(
            match_virtual_device(b"/dev/zero"),
            Some(VirtualDevice::Zero)
        );
        assert_eq!(
            match_virtual_device(b"/dev/urandom"),
            Some(VirtualDevice::Urandom)
        );
        assert_eq!(
            match_virtual_device(b"/dev/random"),
            Some(VirtualDevice::Urandom)
        );
        assert_eq!(
            match_virtual_device(b"/dev/full"),
            Some(VirtualDevice::Full)
        );
        assert_eq!(match_virtual_device(b"/dev/tty"), None);
        assert_eq!(match_virtual_device(b"/tmp/foo"), None);
    }

    #[test]
    fn test_match_dev_fd() {
        assert_eq!(match_dev_fd(b"/dev/stdin"), Some(0));
        assert_eq!(match_dev_fd(b"/dev/stdout"), Some(1));
        assert_eq!(match_dev_fd(b"/dev/stderr"), Some(2));
        assert_eq!(match_dev_fd(b"/dev/fd/0"), Some(0));
        assert_eq!(match_dev_fd(b"/dev/fd/5"), Some(5));
        assert_eq!(match_dev_fd(b"/dev/fd/123"), Some(123));
        assert_eq!(match_dev_fd(b"/dev/fd/"), None);
        assert_eq!(match_dev_fd(b"/dev/fd/abc"), None);
        assert_eq!(match_dev_fd(b"/tmp/foo"), None);
    }

    #[test]
    fn test_virtual_device_roundtrip() {
        for dev in [
            VirtualDevice::Null,
            VirtualDevice::Zero,
            VirtualDevice::Urandom,
            VirtualDevice::Full,
            VirtualDevice::Fb0,
            VirtualDevice::Mice,
            VirtualDevice::Dsp,
            VirtualDevice::DriRenderD128,
            VirtualDevice::DriCard0,
        ] {
            assert_eq!(
                VirtualDevice::from_host_handle(dev.host_handle()),
                Some(dev)
            );
        }
        assert_eq!(VirtualDevice::from_host_handle(0), None);
        // First sentinel past the allocated range — must not roundtrip.
        assert_eq!(VirtualDevice::from_host_handle(-10), None);
    }

