    #[test]
    fn test_timerfd_settime_disarm() {
        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();
        let fd = sys_timerfd_create(&mut proc, 0, 0).unwrap();

        // Set then disarm
        host.clock_time = (100, 0);
        sys_timerfd_settime(&mut proc, &mut host, fd, 0, 0, 0, 105, 0).unwrap();
        let (isec, insec, _vsec, _vnsec) =
            sys_timerfd_settime(&mut proc, &mut host, fd, 0, 0, 0, 0, 0).unwrap();
        // Old value was: interval=(0,0), value was set
        assert_eq!(isec, 0);
        assert_eq!(insec, 0);

        // After disarming, gettime should return all zeros
        let result = sys_timerfd_gettime(&mut proc, &mut host, fd).unwrap();
        assert_eq!(result, (0, 0, 0, 0));
    }

    #[test]
    fn test_timerfd_settime_relative() {
        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();
        let fd = sys_timerfd_create(&mut proc, 0, 0).unwrap();

        host.clock_time = (100, 0);
        // Set timer to expire in 5 seconds (relative)
        let old = sys_timerfd_settime(&mut proc, &mut host, fd, 0, 0, 0, 5, 0).unwrap();
        // Old timer was disarmed
        assert_eq!(old, (0, 0, 0, 0));

        // Timer should now expire at absolute time 105
        let (isec, insec, vsec, vnsec) = sys_timerfd_gettime(&mut proc, &mut host, fd).unwrap();
        assert_eq!(isec, 0);
        assert_eq!(insec, 0);
        assert_eq!(vsec, 5); // 5 seconds remaining
        assert_eq!(vnsec, 0);
    }

    #[test]
    fn test_timerfd_settime_host_error_leaves_backing_unchanged() {
        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();
        let fd = sys_timerfd_create(&mut proc, 0, 0).unwrap();
        let backing_idx = descriptor_backing_idx(&proc, fd);

        sys_timerfd_settime(&mut proc, &mut host, fd, 1, 2, 3, 110, 4).unwrap();
        let before = crate::descriptor_backing::with_timerfds(|table| {
            let timer = table.get(backing_idx).unwrap();
            (
                timer.interval_sec,
                timer.interval_nsec,
                timer.value_sec,
                timer.value_nsec,
                timer.expirations,
            )
        });

        host.clock_error = Some(Errno::EIO);
        assert_eq!(
            sys_timerfd_settime(&mut proc, &mut host, fd, 0, 9, 8, 7, 6),
            Err(Errno::EIO)
        );
        let after = crate::descriptor_backing::with_timerfds(|table| {
            let timer = table.get(backing_idx).unwrap();
            (
                timer.interval_sec,
                timer.interval_nsec,
                timer.value_sec,
                timer.value_nsec,
                timer.expirations,
            )
        });
        assert_eq!(after, before);

        host.clock_error = None;
        sys_close(&mut proc, &mut host, fd).unwrap();
    }

