    #[test]
    fn test_copy_file_range_memfd() {
        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();

        let src = sys_memfd_create(&mut proc, b"src", 0).unwrap();
        let dst = sys_memfd_create(&mut proc, b"dst", 0).unwrap();

        // Write data to source
        sys_write(&mut proc, &mut host, src, b"hello world").unwrap();
        sys_lseek(&mut proc, &mut host, src, 0, SEEK_SET).unwrap();

        // Copy 5 bytes
        let copied = sys_copy_file_range(&mut proc, &mut host, src, None, dst, None, 5).unwrap();
        assert_eq!(copied, 5);

        // Read from destination
        sys_lseek(&mut proc, &mut host, dst, 0, SEEK_SET).unwrap();
        let mut buf = [0u8; 16];
        let n = sys_read(&mut proc, &mut host, dst, &mut buf).unwrap();
        assert_eq!(n, 5);
        assert_eq!(&buf[..5], b"hello");
    }

    #[test]
    fn test_mremap_shrink_in_place() {
        let mut proc = Process::new(1);
        use wasm_posix_shared::mmap::{MAP_ANONYMOUS, MAP_PRIVATE, PROT_READ, PROT_WRITE};
        // mmap 3 pages
        let addr = proc.memory.mmap_anonymous(
            0,
            0x30000,
            PROT_READ | PROT_WRITE,
            MAP_PRIVATE | MAP_ANONYMOUS,
        );
        // Shrink to 1 page
        let new_addr = sys_mremap(&mut proc, addr, 0x30000, 0x10000, 0).unwrap();
        assert_eq!(new_addr, addr);
        assert!(proc.memory.is_mapped(addr));
        assert!(!proc.memory.is_mapped(addr + 0x20000));
    }

    #[test]
    fn test_mremap_grow_in_place() {
        let mut proc = Process::new(1);
        use wasm_posix_shared::mmap::{MAP_ANONYMOUS, MAP_PRIVATE, PROT_READ, PROT_WRITE};
        // mmap 1 page
        let addr = proc.memory.mmap_anonymous(
            0,
            0x10000,
            PROT_READ | PROT_WRITE,
            MAP_PRIVATE | MAP_ANONYMOUS,
        );
        // Grow to 2 pages — should succeed since adjacent space is free
        let new_addr = sys_mremap(&mut proc, addr, 0x10000, 0x20000, 0).unwrap();
        assert_eq!(new_addr, addr);
        assert!(proc.memory.is_mapped(addr + 0x10000));
    }

    #[test]
    fn test_mremap_grow_requires_matching_mapping_metadata() {
        let mut proc = Process::new(1);
        use wasm_posix_shared::mmap::{MAP_ANONYMOUS, MAP_PRIVATE, PROT_READ, PROT_WRITE};
        let addr = proc.memory.mmap_anonymous(
            0,
            0x10000,
            PROT_READ | PROT_WRITE,
            MAP_PRIVATE | MAP_ANONYMOUS,
        );

        // The claimed two-page old range does not match the one-page mapping.
        // A free third page must not turn the missing metadata update into a
        // successful in-place grow.
        assert_eq!(
            sys_mremap(&mut proc, addr, 0x20000, 0x30000, 0).unwrap_err(),
            Errno::EFAULT
        );
        assert_eq!(proc.memory.mappings()[0].len, 0x10000);

        let next = proc.memory.mmap_anonymous(
            0,
            0x10000,
            PROT_READ | PROT_WRITE,
            MAP_PRIVATE | MAP_ANONYMOUS,
        );
        assert_eq!(next, addr + 0x10000);
    }

    #[test]
    fn test_mremap_maymove() {
        let mut proc = Process::new(1);
        use wasm_posix_shared::mmap::{MAP_ANONYMOUS, MAP_PRIVATE, PROT_READ, PROT_WRITE};
        // mmap 1 page
        let addr1 = proc.memory.mmap_anonymous(
            0,
            0x10000,
            PROT_READ | PROT_WRITE,
            MAP_PRIVATE | MAP_ANONYMOUS,
        );
        // mmap another right next to block growth
        let addr2 = proc.memory.mmap_anonymous(
            0,
            0x10000,
            PROT_READ | PROT_WRITE,
            MAP_PRIVATE | MAP_ANONYMOUS,
        );
        assert_eq!(addr2, addr1 + 0x10000);
        // Try to grow with MREMAP_MAYMOVE — should move to new location
        let new_addr = sys_mremap(&mut proc, addr1, 0x10000, 0x20000, 1).unwrap();
        assert_ne!(new_addr, addr1); // moved
        assert!(proc.memory.is_mapped(new_addr));
        assert!(!proc.memory.is_mapped(addr1)); // old freed
        // Note: byte-preservation across the move (the contract that mallocng
        // depends on) cannot be verified here — `proc.memory` is metadata
        // only on the host, and the addresses returned above don't back any
        // real bytes in this test process. The host-side copy is performed
        // in `host/src/kernel-worker.ts`'s SYS_MREMAP post-syscall fixup.
    }

    #[test]
    fn test_mremap_rejects_unsupported_flags() {
        let mut proc = Process::new(1);
        use wasm_posix_shared::mmap::{MAP_ANONYMOUS, MAP_PRIVATE, PROT_READ, PROT_WRITE};
        let addr = proc.memory.mmap_anonymous(
            0,
            0x10000,
            PROT_READ | PROT_WRITE,
            MAP_PRIVATE | MAP_ANONYMOUS,
        );

        // Linux MREMAP_FIXED requires the fifth syscall argument (new_addr),
        // which the current wasm libc import ABI does not pass through. The
        // kernel must reject it rather than accidentally treating the request
        // as an in-place grow at old_addr.
        assert_eq!(
            sys_mremap(&mut proc, addr, 0x10000, 0x20000, 2).unwrap_err(),
            Errno::EINVAL
        );
        assert!(proc.memory.is_mapped(addr));
        assert!(!proc.memory.is_mapped(addr + 0x10000));
    }

