        let (r, _w) = sys_pipe(&mut proc).unwrap();
        // Initially no flags
        let flags = sys_fcntl(&mut proc, r, F_GETFD, 0).unwrap();
        assert_eq!(flags, 0);
        // Set FD_CLOFORK
        sys_fcntl(&mut proc, r, F_SETFD, FD_CLOFORK).unwrap();
