    #[test]
    fn test_procfs_self_stat_open_read_close() {
        let mut proc = Process::new(1);
        proc.argv.push(b"test".to_vec());
        let mut host = MockHostIO::new();

        // open /proc/self/stat
        let fd = sys_open(&mut proc, &mut host, b"/proc/self/stat", O_RDONLY, 0).unwrap();
        assert!(fd >= 3); // after stdio

        // read content
        let mut buf = [0u8; 1024];
        let n = sys_read(&mut proc, &mut host, fd, &mut buf).unwrap();
        assert!(n > 0);
        let content = core::str::from_utf8(&buf[..n]).unwrap();
        assert!(content.starts_with("1 (test) R"));

        // lseek back to start and re-read
        let pos = sys_lseek(&mut proc, &mut host, fd, 0, SEEK_SET).unwrap();
        assert_eq!(pos, 0);
        let n2 = sys_read(&mut proc, &mut host, fd, &mut buf).unwrap();
        assert_eq!(n, n2); // same content (snapshot)

        // fstat
        let st = sys_fstat(&mut proc, &mut host, fd).unwrap();
        assert_eq!(st.st_mode & S_IFMT, S_IFREG);
        assert_eq!(st.st_dev, 0x50);

        // close
        sys_close(&mut proc, &mut host, fd).unwrap();
    }

    #[test]
    fn test_synthetic_mtab_open_read() {
        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();

        let fd = sys_open(&mut proc, &mut host, b"/etc/mtab", O_RDONLY, 0).unwrap();
        let mut buf = [0u8; 256];
        let n = sys_read(&mut proc, &mut host, fd, &mut buf).unwrap();
        let content = core::str::from_utf8(&buf[..n]).unwrap();
        assert!(content.contains("kandelo-root / kandelo-vfs rw 0 0"));
        assert!(content.contains("proc /proc proc rw,nosuid,nodev,noexec 0 0"));
        assert!(content.contains("devfs /dev devfs rw,nosuid 0 0"));

        let st = sys_stat(&mut proc, &mut host, b"/etc/mtab").unwrap();
        assert_eq!(st.st_mode & S_IFMT, S_IFREG);
        assert_eq!(st.st_size as usize, crate::procfs::MOUNTS_CONTENT.len());
        assert!(sys_access(&mut proc, &mut host, b"/etc/mtab", R_OK).is_ok());
        assert_eq!(
            sys_access(&mut proc, &mut host, b"/etc/mtab", W_OK),
            Err(Errno::EACCES),
        );

        sys_close(&mut proc, &mut host, fd).unwrap();
    }

    #[test]
    fn kernel_owned_namespaces_do_not_fall_through_to_hidden_host_entries() {
        let mut proc = Process::new(1);
        let mut host = MockHostIO::new();
        host.set_missing_path(b"/proc/new");
        host.set_missing_path(b"/dev/new");

        assert_eq!(
            sys_open(
                &mut proc,
                &mut host,
                b"/proc/new",
                O_CREAT | O_WRONLY,
                0o600,
            ),
            Err(Errno::EROFS),
        );
        assert_eq!(
            sys_mkdir(&mut proc, &mut host, b"/dev/new", 0o755),
            Err(Errno::EROFS),
        );
        assert_eq!(
            sys_unlink(&mut proc, &mut host, b"/dev/null"),
            Err(Errno::EROFS),
        );
        assert_eq!(
            sys_unlink(&mut proc, &mut host, b"/etc/mtab"),
            Err(Errno::EROFS),
        );
        assert!(sys_stat(&mut proc, &mut host, b"/etc/mtab").is_ok());
    }

