        sys_execve(&mut proc, &mut host, b"/bin/sh").unwrap();
        assert_eq!(
            crate::audio::DSP_OWNER.load(Ordering::SeqCst),
            proc.pid as i32
        );
        assert_eq!(
            crate::audio::pending_bytes(),
            4,
            "exec should retain samples behind a surviving open fd"
        );
